/**
 * Checks if a number is prime.
 * @param {number} num The number to check.
 * @returns {boolean} True if the number is prime, false otherwise.
 */
function isPrime(num) {
    if (num <= 1) return false;
    if (num <= 3) return true;
    if (num % 2 === 0 || num % 3 === 0) return false;
    for (let i = 5; i * i <= num; i = i + 6) {
        if (num % i === 0 || num % (i + 2) === 0) return false;
    }
    return true;
}

/**
 * Reverses the digits of a number.
 * @param {number} n The number to reverse.
 * @returns {number} The reversed number.
 */
function reverseNumber(n) {
    const strN = String(n);
    const reversedStr = strN.split('').reverse().join('');
    return parseInt(reversedStr);
}

/**
 * Finds the sum of all prime numbers between min(n, r) and max(n, r) (inclusive).
 * @param {number} n The input integer.
 * @returns {number} The total sum of primes.
 */
function solve(n) {
    const r = reverseNumber(n);

    const start = Math.min(n, r);
    const end = Math.max(n, r);

    let primeSum = 0;

    for (let i = start; i <= end; i++) {
        if (isPrime(i)) {
            primeSum += i;
        }
    }

    return primeSum;
}
